import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        OrderService svc = new OrderService();
        Order o = svc.createOrder(Arrays.asList(new OrderItem("p1","Book",10.0,2)));
        boolean shipBlocked = !o.ship(new ExpressShipping(), "TRK");
        boolean delBlocked = !o.deliver();
        boolean paid = o.pay(new Payment("PAY1", o.getItemsTotal(), Payment.PaymentMethod.CREDIT_CARD));
        if (shipBlocked && delBlocked && paid) System.out.println("OK_GUARD");
    }
}

/* Test driver */
import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        OrderService svc = new OrderService();
        OrderItem mouse = new OrderItem("p1","Mouse",30.0,1);
        Order o = svc.createOrder(Arrays.asList(mouse));
        o.pay(new Payment("PAY1", o.getItemsTotal(), Payment.PaymentMethod.CREDIT_CARD));
        o.ship(new ExpressShipping(), "TRK-1");
        o.deliver();
        Return r = o.initiateReturn(mouse, Return.ReturnReason.DEFECTIVE);
        Refund refund = o.processRefund(r);
        if (r != null && refund != null) System.out.println("OK_FULLFLOW");
    }
}

